class AuthServicer(microservices_pb2_grpc.AuthServiceServicer):
    """Implements the Auth microservice server-side logic."""

    def Login(self, request, context):
        print(f"AuthService: Received Login request for user: {request.username}")
        if request.username == "testuser" and request.password == "password123":
            # In a real app, generate a proper JWT or session token
            token = f"dummy_auth_token_for_{request.username}"
            print(f"AuthService: User '{request.username}' logged in successfully.")
            return microservices_pb2.LoginResponse(
                success=True, token=token, message="Login successful"
            )
        else:
            print(f"AuthService: Invalid credentials for user: {request.username}")
            return microservices_pb2.LoginResponse(
                success=False, token="", message="Invalid username or password"
            )

class DataServicer(microservices_pb2_grpc.DataServiceServicer):
    """Implements the Data microservice server-side logic."""

    # Dummy data store
    _users_db = {
        "user123": {
            "username": "alice",
            "email": "alice@example.com",
            "token": "dummy_auth_token_for_testuser", # Simplified token validation
        },
        "user456": {
            "username": "bob",
            "email": "bob@example.com",
            "token": "some_other_token",
        },
    }

    def GetUserData(self, request, context):
        print(f"DataService: Received GetUserData request for user_id: {request.user_id}")

        user_data = self._users_db.get(request.user_id)
        if user_data:
            # Simple token validation (in real app, validate JWT)
            if request.auth_token == user_data["token"]:
                print(f"DataService: Found data for user_id: {request.user_id}")
                return microservices_pb2.UserDataResponse(
                    success=True,
                    user_id=request.user_id,
                    username=user_data["username"],
                    email=user_data["email"],
                    message="User data retrieved successfully",
                )
            else:
                print(f"DataService: Invalid auth token for user_id: {request.user_id}")
                return microservices_pb2.UserDataResponse(
                    success=False, message="Unauthorized: Invalid or expired token"
                )
        else:
            print(f"DataService: User_id {request.user_id} not found.")
            return microservices_pb2.UserDataResponse(
                success=False, message="User not found"
            )

def serve():
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    microservices_pb2_grpc.add_AuthServiceServicer_to_server(AuthServicer(), server)
    microservices_pb2_grpc.add_DataServiceServicer_to_server(DataServicer(), server)
    server.add_insecure_port("[::]:50051")
    server.start()
    print("gRPC Server started on port 50051. Awaiting client requests...")
    try:
        while True:
            time.sleep(_ONE_DAY_IN_SECONDS)
    except KeyboardInterrupt:
        server.stop(0)
        print("gRPC Server stopped.")

if __name__ == "__main__":
    serve()

